import requests

def get_users_with_message_counts():
    channels = {"function": "get_channels", "args": []}
    response = requests.post('http://localhost:5000/api/execute', json=channels)
    channels = response.json()

    user_messages = {}

    for channel in channels:
        messages = {"function": "read_channel_messages", "args": [channel]}
        response = requests.post('http://localhost:5000/api/execute', json=messages)
        messages = response.json()

        for message in messages:
            if message['sender'] not in user_messages:
                user_messages[message['sender']] = 0
            user_messages[message['sender']] += 1

    sorted_users = sorted(user_messages.items(), key=lambda x: (-x[1], x[0]))

    # Send direct messages
    for i, (user, count) in enumerate(sorted_users):
        message = f"Congrats on being the {i+1}-th most active user!"
        data = {"function": "send_direct_message", "args": [user, message]}
        response = requests.post('http://localhost:5000/api/execute', json=data)

get_users_with_message_counts()
